const response = $input.first().json;
const items = response.items || [];

// Pagination
let nextStartIndex = 1;
if (response.queries?.nextPage?.[0]) {
  nextStartIndex = response.queries.nextPage[0].startIndex;
}

const hasMoreResults = nextStartIndex <= 100 && nextStartIndex <= ($('Set - Search Parameters').item.json.maxPages * 10);

// Extraction jobs
const jobs = items.map(item => {
  // Parser titre LinkedIn: "Job Title - Company Name | LinkedIn"
  const titleParts = item.title.split(' - ');
  const title = titleParts[0]?.trim() || 'Non spécifié';
  const companyPart = titleParts[1]?.split('|')[0]?.trim() || 'Non spécifié';

  return {
    title: title,
    company: companyPart,
    location: extractLocation(item.snippet),
    raw_description: item.snippet || '',
    url: item.link,
    source: 'LinkedIn',
    scraping_source: 'linkedin_google',
    scraping_method: 'google_custom_search',
    scraped_at: new Date().toISOString(),
    // Pagination info
    startIndex: nextStartIndex,
    hasMoreResults: hasMoreResults
  };
});

function extractLocation(snippet) {
  // Patterns communs LinkedIn
  const patterns = [
    /(?:in|à|at)\s+([A-Z][a-zé]+(?:,\s*[A-Z][a-z]+)?)/,
    /([A-Z][a-zé]+,\s*France)/,
    /(Paris|Lyon|Marseille|Toulouse|Bordeaux|Lille|Nantes)/i
  ];

  for (const pattern of patterns) {
    const match = snippet.match(pattern);
    if (match) return match[1] || match[0];
  }

  return 'Non spécifié';
}

console.log(`✅ [LinkedIn Google] Jobs extraits: ${jobs.length}`);
console.log(`📄 Pagination: ${nextStartIndex}, hasMore: ${hasMoreResults}`);

if (jobs.length === 0) {
  return [{ json: { error: 'No jobs found', hasMoreResults: false } }];
}

return jobs.map(j => ({ json: j }));

